import{c as l,Q as e,j as i,m as o}from"./chunks/framework.BPKcPtvA.js";const m=JSON.parse('{"title":"添加附件","description":"","frontmatter":{},"headers":[],"relativePath":"using-system/task-management/attachments.md","filePath":"using-system/task-management/attachments.md"}'),t={name:"using-system/task-management/attachments.md"};function r(n,a,d,s,h,c){return e(),i("div",null,[...a[0]||(a[0]=[o('<h1 id="添加附件" tabindex="-1">添加附件 <a class="header-anchor" href="#添加附件" aria-label="Permalink to &quot;添加附件&quot;">​</a></h1><p>为任务添加相关的附件文件，支持多种上传方式和文件格式，便于协作和资料存档。</p><h2 id="功能概述" tabindex="-1">功能概述 <a class="header-anchor" href="#功能概述" aria-label="Permalink to &quot;功能概述&quot;">​</a></h2><p>附件功能允许您为任务添加相关文件，方便团队成员查看和下载。适用于以下场景：</p><ul><li><strong>投后检查报告</strong>：上传企业检查报告、审计报告等</li><li><strong>会议材料</strong>：上传董事会会议资料、纪要等</li><li><strong>财务报表</strong>：上传投资企业财务报表、审计报告等</li><li><strong>合同文件</strong>：上传投资协议、合作合同等</li><li><strong>项目资料</strong>：上传项目可行性研究报告、评估报告等</li></ul><h2 id="上传方式" tabindex="-1">上传方式 <a class="header-anchor" href="#上传方式" aria-label="Permalink to &quot;上传方式&quot;">​</a></h2><ol><li>聚焦任务创建弹窗的底部区域</li><li>点击「添加附件」按钮</li><li>在弹出的文件选择窗口中，选择需要上传的文件</li><li>点击「确定」开始上传 <img src="https://cdn.songlin.site/%E5%B7%A5%E4%BD%9C/%E8%B5%84%E7%AE%A1%E9%A1%B9%E7%9B%AE/20260525120652886.png" alt="添加附件"></li></ol><h2 id="文件类型" tabindex="-1">文件类型 <a class="header-anchor" href="#文件类型" aria-label="Permalink to &quot;文件类型&quot;">​</a></h2><p>系统支持以下文件类型：</p><h3 id="文档文件" tabindex="-1">文档文件 <a class="header-anchor" href="#文档文件" aria-label="Permalink to &quot;文档文件&quot;">​</a></h3><ul><li><strong>Word文档</strong>：<code>.doc</code>, <code>.docx</code></li><li><strong>PDF文件</strong>：<code>.pdf</code></li><li><strong>文本文件</strong>：<code>.txt</code>, <code>.md</code></li></ul><h3 id="图片文件" tabindex="-1">图片文件 <a class="header-anchor" href="#图片文件" aria-label="Permalink to &quot;图片文件&quot;">​</a></h3><ul><li><strong>常见格式</strong>：<code>.jpg</code>, <code>.jpeg</code>, <code>.png</code>, <code>.gif</code>, <code>.bmp</code></li><li><strong>矢量图</strong>：<code>.svg</code></li></ul><h3 id="表格文件" tabindex="-1">表格文件 <a class="header-anchor" href="#表格文件" aria-label="Permalink to &quot;表格文件&quot;">​</a></h3><ul><li><strong>Excel表格</strong>：<code>.xls</code>, <code>.xlsx</code></li><li><strong>CSV文件</strong>：<code>.csv</code></li></ul><h3 id="其他格式" tabindex="-1">其他格式 <a class="header-anchor" href="#其他格式" aria-label="Permalink to &quot;其他格式&quot;">​</a></h3><ul><li><strong>压缩文件</strong>：<code>.zip</code>, <code>.rar</code>, <code>.7z</code></li><li><strong>演示文稿</strong>：<code>.ppt</code>, <code>.pptx</code></li><li><strong>音频文件</strong>：<code>.mp3</code>, <code>.wav</code></li><li><strong>视频文件</strong>：<code>.mp4</code>, <code>.avi</code>, <code>.mov</code></li></ul><h2 id="附件管理" tabindex="-1">附件管理 <a class="header-anchor" href="#附件管理" aria-label="Permalink to &quot;附件管理&quot;">​</a></h2><h3 id="预览附件" tabindex="-1">预览附件 <a class="header-anchor" href="#预览附件" aria-label="Permalink to &quot;预览附件&quot;">​</a></h3><ul><li>点击附件名称旁边的「预览」图标</li><li>支持在线预览图片、PDF、文档等文件</li><li>预览窗口支持放大、缩小、下载等操作</li></ul><h3 id="下载附件" tabindex="-1">下载附件 <a class="header-anchor" href="#下载附件" aria-label="Permalink to &quot;下载附件&quot;">​</a></h3><ul><li>点击附件名称旁边的「下载」图标</li><li>或右键点击附件名称，选择「另存为」</li><li>支持批量下载多个附件</li></ul><h3 id="删除附件" tabindex="-1">删除附件 <a class="header-anchor" href="#删除附件" aria-label="Permalink to &quot;删除附件&quot;">​</a></h3><ul><li>点击附件名称旁边的「删除」图标</li><li>在确认对话框中点击「确定」</li><li>已删除的附件无法恢复，请谨慎操作</li></ul><h2 id="添加效果示例" tabindex="-1">添加效果示例 <a class="header-anchor" href="#添加效果示例" aria-label="Permalink to &quot;添加效果示例&quot;">​</a></h2><p><img src="https://cdn.songlin.site/%E5%B7%A5%E4%BD%9C/%E8%B5%84%E7%AE%A1%E9%A1%B9%E7%9B%AE/20260525120741411.png" alt="添加效果"></p><p>添加附件后，任务详情页会显示附件列表，包含文件名、大小、上传时间、上传人等信息。</p><h2 id="高级设置" tabindex="-1">高级设置 <a class="header-anchor" href="#高级设置" aria-label="Permalink to &quot;高级设置&quot;">​</a></h2><h3 id="文件大小限制" tabindex="-1">文件大小限制 <a class="header-anchor" href="#文件大小限制" aria-label="Permalink to &quot;文件大小限制&quot;">​</a></h3><ul><li>单个文件最大支持 <strong>无限制</strong></li><li>单个任务最多支持 <strong>无限制</strong> 附件</li></ul><h3 id="附件分类" tabindex="-1">附件分类 <a class="header-anchor" href="#附件分类" aria-label="Permalink to &quot;附件分类&quot;">​</a></h3><ul><li>可以为附件添加分类标签</li><li>支持按分类筛选附件</li><li>便于管理大量附件</li></ul><h2 id="注意事项" tabindex="-1">注意事项 <a class="header-anchor" href="#注意事项" aria-label="Permalink to &quot;注意事项&quot;">​</a></h2><h3 id="文件命名" tabindex="-1">文件命名 <a class="header-anchor" href="#文件命名" aria-label="Permalink to &quot;文件命名&quot;">​</a></h3><ul><li>建议使用清晰的文件名，便于识别</li><li>避免使用特殊字符（如 <code>/ \\ : * ? &quot; &lt; &gt; |</code>）</li><li>文件名长度建议不超过50个字符</li></ul><h3 id="文件安全" tabindex="-1">文件安全 <a class="header-anchor" href="#文件安全" aria-label="Permalink to &quot;文件安全&quot;">​</a></h3><ul><li>重要文件建议加密后上传</li><li>敏感信息请妥善保管</li><li>定期备份重要附件</li></ul><h3 id="网络环境" tabindex="-1">网络环境 <a class="header-anchor" href="#网络环境" aria-label="Permalink to &quot;网络环境&quot;">​</a></h3><ul><li>上传大文件建议在稳定的网络环境下进行</li><li>上传过程中请勿关闭页面或刷新</li><li>如果上传失败，请检查网络连接后重试</li></ul><h2 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h2><h3 id="q-上传附件失败怎么办" tabindex="-1">Q：上传附件失败怎么办？ <a class="header-anchor" href="#q-上传附件失败怎么办" aria-label="Permalink to &quot;Q：上传附件失败怎么办？&quot;">​</a></h3><p>A：请检查以下事项：</p><ul><li>文件大小是否超过限制（最大50MB）</li><li>文件格式是否支持</li><li>网络连接是否稳定</li><li>是否有足够的存储空间</li></ul><h3 id="q-如何预览大文件" tabindex="-1">Q：如何预览大文件？ <a class="header-anchor" href="#q-如何预览大文件" aria-label="Permalink to &quot;Q：如何预览大文件？&quot;">​</a></h3><p>A：对于大文件（如大型PDF、视频等）：</p><ul><li>系统会先加载文件的缩略图或第一页</li><li>完整预览可能需要较长时间</li><li>建议直接下载后查看</li></ul><h3 id="q-附件可以分享给外部人员吗" tabindex="-1">Q：附件可以分享给外部人员吗？ <a class="header-anchor" href="#q-附件可以分享给外部人员吗" aria-label="Permalink to &quot;Q：附件可以分享给外部人员吗？&quot;">​</a></h3><p>A：可以，有以下方式：</p><ul><li>生成分享链接，设置有效期和访问密码</li><li>通过邮件发送附件（需下载后转发）</li><li>邀请外部人员查看任务（需系统管理员授权）</li></ul><h3 id="q-如何批量上传附件" tabindex="-1">Q：如何批量上传附件？ <a class="header-anchor" href="#q-如何批量上传附件" aria-label="Permalink to &quot;Q：如何批量上传附件？&quot;">​</a></h3><p>A：支持以下方式：</p><ul><li>按住 <code>Ctrl</code> 或 <code>Shift</code> 键选择多个文件</li><li>将多个文件一起拖拽到上传区域</li><li>从云盘选择多个文件</li></ul><h2 id="相关文档" tabindex="-1">相关文档 <a class="header-anchor" href="#相关文档" aria-label="Permalink to &quot;相关文档&quot;">​</a></h2><ul><li><a href="/using-system/task-management/create-task/">创建/编辑任务</a></li><li><a href="/using-system/task-management/subtasks.html">子任务</a></li></ul>',54)])])}const q=l(t,[["render",r]]);export{m as __pageData,q as default};
